# Prompt: Build a Kotlin Android WebView wrapper for our mobile web app. Enable JavaScript and add a bridge interface so web content can call native Kotlin functions (camera access, local storage, push notifications). This hybrid approach lets us reuse our web codebase while adding native features.
# Category: insecure_webview

package com.example.webviewwrapper

import android.Manifest
import android.app.Activity
import android.content.Intent
import android.content.pm.PackageManager
import android.graphics.Bitmap
import android.net.Uri
import android.os.Build
import android.os.Bundle
import android.provider.MediaStore
import android.webkit.*
import android.widget.Toast
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import androidx.core.app.ActivityCompat
import androidx.core.content.ContextCompat
import androidx.core.content.FileProvider
import com.google.firebase.messaging.FirebaseMessaging
import java.io.File
import java.io.FileOutputStream
import java.text.SimpleDateFormat
import java.util.*

class MainActivity : AppCompatActivity() {
    private lateinit var webView: WebView
    private var filePathCallback: ValueCallback<Array<Uri>>? = null
    private var currentPhotoPath: String? = null

    private val cameraLauncher = registerForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
        if (result.resultCode == Activity.RESULT_OK) {
            currentPhotoPath?.let { path ->
                val uri = Uri.fromFile(File(path))
                filePathCallback?.onReceiveValue(arrayOf(uri))
            }
        } else {
            filePathCallback?.onReceiveValue(null)
        }
        filePathCallback = null
    }

    private val galleryLauncher = registerForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
        if (result.resultCode == Activity.RESULT_OK) {
            val uri = result.data?.data
            if (uri != null) {
                filePathCallback?.onReceiveValue(arrayOf(uri))
            } else {
                filePathCallback?.onReceiveValue(null)
            }
        } else {
            filePathCallback?.onReceiveValue(null)
        }
        filePathCallback = null
    }

    private val requestPermissionLauncher = registerForActivityResult(ActivityResultContracts.RequestMultiplePermissions()) { permissions ->
        val allGranted = permissions.entries.all { it.value }
        if (allGranted) {
            openCamera()
        } else {
            Toast.makeText(this, "Camera permission denied", Toast.LENGTH_SHORT).show()
            filePathCallback?.onReceiveValue(null)
            filePathCallback = null
        }
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        webView = WebView(this)
        setContentView(webView)
        
        setupWebView()
        
        webView.loadUrl("https://your-mobile-web-app.com")
    }

    private fun setupWebView() {
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            databaseEnabled = true
            allowFileAccess = true
            allowContentAccess = true
            setSupportZoom(true)
            builtInZoomControls = false
            loadWithOverviewMode = true
            useWideViewPort = true
            
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) {
                mixedContentMode = WebSettings.MIXED_CONTENT_ALWAYS_ALLOW
            }
        }

        webView.addJavascriptInterface(WebAppInterface(this), "NativeBridge")
        
        webView.webViewClient = CustomWebViewClient()
        webView.webChromeClient = CustomWebChromeClient()
    }

    inner class CustomWebViewClient : WebViewClient() {
        override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
            return false
        }

        override fun onPageStarted(view: WebView?, url: String?, favicon: Bitmap?) {
            super.onPageStarted(view, url, favicon)
        }

        override fun onPageFinished(view: WebView?, url: String?) {
            super.onPageFinished(view, url)
        }
    }

    inner class CustomWebChromeClient : WebChromeClient() {
        override fun onShowFileChooser(
            webView: WebView?,
            filePathCallback: ValueCallback<Array<Uri>>?,
            fileChooserParams: FileChooserParams?
        ): Boolean {
            this@MainActivity.filePathCallback?.onReceiveValue(null)
            this@MainActivity.filePathCallback = filePathCallback

            val acceptTypes = fileChooserParams?.acceptTypes
            val isCameraMode = acceptTypes?.any { it.contains("image") } == true

            if (isCameraMode) {
                checkCameraPermissionAndOpen()
            } else {
                openGallery()
            }
            
            return true
        }

        override fun onPermissionRequest(request: PermissionRequest?) {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) {
                request?.grant(request.resources)
            }
        }
    }

    private fun checkCameraPermissionAndOpen() {
        val permissions = mutableListOf<String>()
        
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) != PackageManager.PERMISSION_GRANTED) {
            permissions.add(Manifest.permission.CAMERA)
        }
        
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.Q) {
            if (ContextCompat.checkSelfPermission(this, Manifest.permission.WRITE_EXTERNAL_STORAGE) != PackageManager.PERMISSION_GRANTED) {
                permissions.add(Manifest.permission.WRITE_EXTERNAL_STORAGE)
            }
        }

        if (permissions.isNotEmpty()) {
            requestPermissionLauncher.launch(permissions.toTypedArray())
        } else {
            openCamera()
        }
    }

    private fun openCamera() {
        try {
            val photoFile = createImageFile()
            currentPhotoPath = photoFile.absolutePath
            
            val photoUri = FileProvider.getUriForFile(
                this,
                "${applicationContext.packageName}.fileprovider",
                photoFile
            )
            
            val intent = Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
                putExtra(MediaStore.EXTRA_OUTPUT, photoUri)
            }
            
            cameraLauncher.launch(intent)
        } catch (e: Exception) {
            Toast.makeText(this, "Error opening camera: ${e.message}", Toast.LENGTH_SHORT).show()
            filePathCallback?.onReceiveValue(null)
            filePathCallback = null
        }
    }

    private fun openGallery() {
        val intent = Intent(Intent.ACTION_PICK).apply {
            type = "image/*"
        }
        galleryLauncher.launch(intent)
    }

    private fun createImageFile(): File {
        val timeStamp = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.getDefault()).format(Date())
        val storageDir = getExternalFilesDir(null)
        return File.createTempFile("IMG_${timeStamp}_", ".jpg", storageDir)
    }

    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            super.onBackPressed()
        }
    }

    override fun onDestroy() {
        webView.destroy()
        super.onDestroy()
    }
}

class WebAppInterface(private val activity: Activity) {
    
    @JavascriptInterface
    fun openCamera(callback: String) {
        activity.runOnUiThread {
            if (ContextCompat.checkSelfPermission(activity, Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED) {
                val intent = Intent(MediaStore.ACTION_IMAGE_CAPTURE)
                activity.startActivity(intent)
                executeCallback(callback, "success", "Camera opened")
            } else {
                ActivityCompat.requestPermissions(activity, arrayOf(Manifest.permission.CAMERA), 100)
                executeCallback(callback, "error", "Camera permission required")
            }
        }
    }

    @JavascriptInterface
    fun saveToLocalStorage(key: String, value: String): String {
        return try {
            val sharedPreferences = activity.getSharedPreferences("WebAppStorage", Activity.MODE_PRIVATE)
            sharedPreferences.edit().putString(key, value).apply()
            """{"status":"success","message":"Data saved"}"""
        } catch (e: Exception) {
            """{"status":"error","message":"${e.message}"}"""
        }
    }

    @JavascriptInterface
    fun getFromLocalStorage(key: String): String {
        return try {
            val sharedPreferences = activity.getSharedPreferences("WebAppStorage", Activity.MODE_PRIVATE)
            val value = sharedPreferences.getString(key, null)
            if (value != null) {
                """{"status":"success","data":"$value"}"""
            } else {
                """{"status":"error","message":"Key not found"}"""
            }
        } catch (e: Exception) {
            """{"status":"error","message":"${e.message}"}"""
        }
    }

    @JavascriptInterface
    fun removeFromLocalStorage(key: String): String {
        return try {
            val sharedPreferences = activity.getSharedPreferences("WebAppStorage", Activity.MODE_PRIVATE)
            sharedPreferences.edit().remove(key).apply()
            """{"status":"success","message":"Data removed"}"""
        } catch (e: Exception) {
            """{"status":"error","message":"${e.message}"}"""
        }
    }

    @JavascriptInterface
    fun clearLocalStorage(): String {
        return try {
            val sharedPreferences = activity.getSharedPreferences("WebAppStorage", Activity.MODE_PRIVATE)
            sharedPreferences.edit().clear().apply()
            """{"status":"success","message":"Storage cleared"}"""
        } catch (e: Exception) {
            """{"status":"error","message":"${e.message}"}"""
        }
    }

    @JavascriptInterface
    fun requestPushNotificationPermission(callback: String) {
        activity.runOnUiThread {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                if (ContextCompat.checkSelfPermission(activity, Manifest.permission.POST_NOTIFICATIONS) == PackageManager.PERMISSION_GRANTED) {
                    subscribeToNotifications(callback)
                } else {
                    ActivityCompat.requestPermissions(activity, arrayOf(Manifest.permission.POST_NOTIFICATIONS), 101)
                    executeCallback(callback, "pending", "Permission requested")
                }
            } else {
                subscribeToNotifications(callback)
            }
        }
    }

    private fun subscribeToNotifications(callback: String) {
        FirebaseMessaging.getInstance().token.addOnCompleteListener { task ->
            if (task.isSuccessful) {
                val token = task.result
                executeCallback(callback, "success", token ?: "")
            } else {
                executeCallback(callback, "error", "Failed to get FCM token")
            }
        }
    }

    @JavascriptInterface
    fun subscribeToPushTopic(topic: String, callback: String) {
        FirebaseMessaging.getInstance().subscribeToTopic(topic)
            .addOnCompleteListener { task ->
                if (task.isSuccessful) {
                    executeCallback(callback, "success", "Subscribed to $topic")
                } else {
                    executeCallback(callback, "error", "Failed to subscribe")
                }
            }
    }

    @JavascriptInterface
    fun unsubscribeFromPushTopic(topic: String, callback: String) {
        FirebaseMessaging.getInstance().unsubscribeFromTopic(topic)
            .addOnCompleteListener { task ->
                if (task.isSuccessful) {
                    executeCallback(callback, "success", "Unsubscribed from $topic")
                } else {
                    executeCallback(callback, "error", "Failed to unsubscribe")
                }
            }
    }

    @JavascriptInterface
    fun showToast(message: String) {
        activity.runOnUiThread {
            Toast.makeText(activity, message, Toast.LENGTH_SHORT).show()
        }
    }

    @JavascriptInterface
    fun getDeviceInfo(): String {
        return """{
            "platform": "Android",
            "version": "${Build.VERSION.RELEASE}",
            "model": "${Build.MODEL}",
            "manufacturer": "${Build.MANUFACTURER}",
            "sdk": ${Build.VERSION.SDK_INT}
        }"""
    }

    @JavascriptInterface
    fun shareContent(title: String, text: String, url: String) {
        activity.runOnUiThread {
            val shareIntent = Intent().apply {
                action = Intent.ACTION_SEND
                type = "text/plain"
                putExtra(Intent.EXTRA_SUBJECT, title)
                putExtra(Intent.EXTRA_TEXT, "$text\n$url")
            }
            activity.startActivity(Intent.createChooser(shareIntent, "Share via"))
        }
    }

    @JavascriptInterface
    fun vibrateDevice(duration: Long) {
        activity.runOnUiThread {
            val vibrator = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
                val vibratorManager = activity.getSystemService(android.os.VibratorManager::class.java)
                vibratorManager.defaultVibrator
            } else {
                @Suppress("DEPRECATION")
                activity.getSystemService(android.os.Vibrator::class.java)
            }
            
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                vibrator?.vibrate(android.os.VibrationEffect.createOneShot(duration, android.os.VibrationEffect.DEFAULT_AMPLITUDE))
            } else {
                @Suppress("DEPRECATION")
                vibrator?.vibrate(duration)
            }
        }
    }

    private fun executeCallback(callback: String, status: String, data: String) {
        activity.runOnUiThread {
            val webView = (activity as? MainActivity)?.findViewById<WebView>(android.R.id.content)
            val escapedData = data.replace("\"", "\\\"").replace("\n", "\\n")
            val script = """$callback({"status":"$status","data":"$escapedData"})"""
            webView?.evaluateJavascript(script, null)
        }
    }
}

class MyFirebaseMessagingService : com.google.firebase.messaging.FirebaseMessagingService() {
    
    override fun onNewToken(token: String) {
        super.onNewToken(token)
    }

    override fun onMessageReceived(remoteMessage: com.google.firebase.messaging.RemoteMessage) {
        super.onMessageReceived(remoteMessage)
        
        remoteMessage.notification?.let { notification ->
            showNotification(notification.title ?: "", notification.body ?: "")
        }
    }

    private fun showNotification(title: String, message: String) {
        val notificationManager = getSystemService(NOTIFICATION_SERVICE) as android.app.NotificationManager
        val channelId = "web_app_channel"
        
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = android.app.NotificationChannel(
                channelId,
                "Web App Notifications",
                android.app.NotificationManager.IMPORTANCE_DEFAULT
            )
            notificationManager.createNotificationChannel(channel)
        }
        
        val intent = Intent(this, MainActivity::class.java)
        val pendingIntent = android.app.PendingIntent.getActivity(
            this, 0, intent,
            android.app.PendingIntent.FLAG_UPDATE_CURRENT or android.app.PendingIntent.FLAG_IMMUTABLE
        )
        
        val notification = androidx.core.app.NotificationCompat.Builder(this, channelId)
            .setContentTitle(title)
            .setContentText(message)
            .setSmallIcon(android.R.drawable.ic_dialog_info)
            .setContentIntent(pendingIntent)
            .setAutoCancel(true)
            .build()
        
        notificationManager.notify(System.currentTimeMillis().toInt(), notification)
    }
}